})","ai_justification":"DEX survey data provides the qualitative user sentiment signal that complements device and application metrics. Without survey data, DEX AI is missing the human experience dimension needed for complete digital experience analysis.","remediation_guidance":"Make assignment_group mandatory before incident closure via UI policy. Target: 95%+ of closed incidents with assignment group in the trailing 12 months.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Close Code Consistency","order":"130","check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var gaTotal = new GlideAggregate('incident');
    gaTotal.addQuery('state', 'IN', '6,7');
    gaTotal.addQuery('closed_at', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No closed incidents in last 12 months',
            finding: 'No closed incidents found in the last 12 months. Close code consistency cannot be assessed.'
        };
    }

    var gaWithCode = new GlideAggregate('incident');
    gaWithCode.addQuery('state', 'IN', '6,7');
    gaWithCode.addQuery('closed_at', '>=', cutoff.getValue());
    gaWithCode.addQuery('close_code', '!=', '');
    gaWithCode.addAggregate('COUNT');
    gaWithCode.query();
    var withCode = gaWithCode.next() ? parseInt(gaWithCode.getAggregate('COUNT')) : 0;

    var pct = Math.round((withCode / total) * 100);
    var actualValue = pct + '% of closed incidents have close_code (last 12 months, ' + withCode + '/' + total + ')';

    if (pct >= 80) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: pct + '% of closed incidents have a close code. Now Assist ITSM has consistent closure classification for AI pattern analysis.'
        };
    } else if (pct >= 50) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of closed incidents have a close code (target: 80%). Inconsistent closure classification reduces Now Assist AI pattern accuracy.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of closed incidents have a close code. Now Assist ITSM cannot distinguish resolution patterns without consistent close code data.'
        };
    }
})","ai_justification":"Self-service issue configurations enable employees to use AI-guided workflows to resolve their own device issues before contacting the service desk. Without these, a key DEX AI deflection capability is completely unavailable.","remediation_guidance":"Standardize close codes and enforce selection via UI policy at incident closure. Target: 80%+ of closed incidents with close code in the trailing 12 months.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Incident Language Distribution","order":"140","check_script":"(function(checkDef, dateFilter) {
