        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + total + ' change requests in the last 12 months. Insufficient change history for meaningful Now Assist change risk assessment AI learning.'
        };
    }
})","ai_justification":"Sufficient change history allows Now Assist to learn risk patterns, generate accurate change summaries, and provide AI-assisted risk assessments grounded in historical data.","remediation_guidance":"Allow change record volume to accumulate before enabling Now Assist change risk assessment features. Focus on data quality: descriptions, CI association, and closure notes. Target: 500+ change requests in the trailing 12 months.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Change Record Data Completeness","order":"280","check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var gaTotal = new GlideAggregate('change_request');
    gaTotal.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No change requests in last 12 months',
            finding: 'No change requests found in the last 12 months. Change data completeness cannot be assessed.'
        };
    }

    var gaMissingDesc = new GlideAggregate('change_request');
    gaMissingDesc.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaMissingDesc.addQuery('short_description', '');
    gaMissingDesc.addAggregate('COUNT');
    gaMissingDesc.query();
    var missingDesc = gaMissingDesc.next() ? parseInt(gaMissingDesc.getAggregate('COUNT')) : 0;

    var descPct = Math.round((missingDesc / total) * 100);
