    if (descPct <= 5) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: 'Only ' + descPct + '% of recent change requests are missing descriptions. Now Assist change summarization has strong text content for AI risk assessment.'
        };
    } else if (descPct <= 20) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: descPct + '% of recent change requests are missing descriptions (target: ≤5%). Now Assist change risk assessment will have gaps for undescribed changes.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: descPct + '% of recent change requests are missing descriptions. Now Assist change summarization reads short_description for AI risk assessment — critical data gap.'
        };
    }
})","ai_justification":"Now Assist change summarization reads description, risk, impact, and assignment_group. Well-populated change records enable AI-generated risk assessments with real specificity.","remediation_guidance":"Enforce short_description as mandatory at change creation via UI policy. Target: ≤5% of changes missing descriptions in the trailing 12 months. Now Assist change summarization reads this field to generate AI risk assessments.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Change-to-CI Association Rate","order":"290","check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addYearsUTC(-1);

    var gaTotal = new GlideAggregate('change_request');
    gaTotal.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No change requests in last 12 months',
            finding: 'No change requests found in the last 12 months. CI association rate cannot be assessed.'
        };
    }

    var gaMissing = new GlideAggregate('change_request');
    gaMissing.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaMissing.addQuery('cmdb_ci', '');
    gaMissing.addAggregate('COUNT');
    gaMissing.query();
    var missing = gaMissing.next() ? parseInt(gaMissing.getAggregate('COUNT')) : 0;

    var withCI = total - missing;
    var pct = Math.round((withCI / total) * 100);
    var actualValue = pct + '% of change requests have CI associated (last 12 months, ' + withCI + '/' + total + ')';

    if (pct >= 80) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: pct + '% of recent change requests are linked to a CI. Now Assist can calculate infrastructure blast radius for AI change risk assessment.'
        };
    } else if (pct >= 50) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of change requests have a CI linked (target: 80%). Now Assist change risk assessment will have incomplete blast radius analysis for unlinked changes.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of change requests have a CI linked. Now Assist cannot calculate infrastructure blast radius without CI association — change risk AI assessment will be severely limited.'
        };
    }
})","ai_justification":"CI association enables Now Assist to traverse CMDB relationships and calculate infrastructure blast radius for each change -- the foundation of AI-driven change risk analysis.","remediation_guidance":"Make cmdb_ci mandatory at change creation via UI policy. Target: 80%+ of change requests with CI association in the trailing 12 months. CI association enables Now Assist to calculate infrastructure blast radius for each change.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Change Model Usage","order":"300","check_script":"(function(checkDef, dateFilter) {
    var ga = new GlideAggregate('chg_model');
    ga.addQuery('active', true);
    ga.addAggregate('COUNT');
    ga.query();
    var count = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = count + ' active change models configured';

    if (count >= 3) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: count + ' active change models. Now Assist AI Agent has well-defined rules for scoping risk reasoning and routing approvals across change types.'
        };
    } else if (count >= 1) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + count + ' active change model(s) (target: 3+). Now Assist AI Agent change handling will have limited differentiation across change types.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'No active change models. Now Assist AI Agent uses change models to scope risk reasoning and route approvals — without them all changes are treated identically.'
        };
    }
})","ai_justification":"Change models define the rules Now Assist ITSM AI Agent uses to scope risk reasoning and route approvals. Without them the AI applies generic logic regardless of change type.","remediation_guidance":"Configure active change models via chg_model_list.do for Normal, Standard, and Emergency change types at minimum. Change models define the rules Now Assist AI Agent uses to scope risk reasoning and route approvals.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Incident-to-Problem Linkage Rate","order":"310","check_script":"(function(checkDef, dateFilter) {
    // Count total closed/resolved problems
    // OOB problem closed states: 3 = Closed/Resolved, 4 = Closed
    // Some instances use additional values -- we use 3,4 as the broadest OOB closed set
    var totalGr = new GlideAggregate("problem");
    totalGr.addQuery("state", "IN", "3,4");
    totalGr.addAggregate("COUNT");
    totalGr.query();
    var total = totalGr.next() ? parseInt(totalGr.getAggregate("COUNT")) : 0;

    if (total === 0) {
        return { status: "not_applicable",
            actualValue: "No closed problem records found (state IN 3,4)",
            finding: "No closed problem records found. Incident-to-Problem linkage cannot be assessed." };
    }

    // Count distinct problems that have at least one incident linked
    // via incident.problem_id -- the OOB linkage mechanism
    var linkedProblems = 0;
    try {
        var linkedGr = new GlideAggregate("incident");
        linkedGr.addQuery("problem_id", "!=", "");
        linkedGr.addAggregate("COUNT", "problem_id");
        linkedGr.groupBy("problem_id");
        linkedGr.query();
        while (linkedGr.next()) { linkedProblems++; }
    } catch(e) { linkedProblems = 0; }

    var pct = Math.round((linkedProblems / total) * 100);
    var actualValue = linkedProblems + " of " + total + " problems have linked incidents via incident.problem_id (" + pct + "% linkage coverage)";

    if (pct >= 50) {
        return { status: "ready", actualValue: actualValue,
            finding: pct + "% of problems have linked incidents. Now Assist problem summarization has adequate incident context for root cause pattern analysis." };
    } else if (pct >= 20) {
        return { status: "needs_attention", actualValue: actualValue,
            finding: "Only " + pct + "% of problems are linked to incidents (target: 50%+). Now Assist problem analysis will lack context for unlinked records. Ensure the Problem field on Incident records is populated when incidents are escalated." };
    } else {
        return { status: "not_ready", actualValue: actualValue,
            finding: "Only " + pct + "% of problems have linked incidents. Now Assist cannot surface root cause patterns without incident context on problem records. Link incidents to problems via incident.problem_id." };
    }
})()","ai_justification":"Now Assist problem summarization aggregates incident patterns to identify root cause trends. With 0 structured incident-problem relationships, the AI has no linkage data to reason from.","remediation_guidance":"Ensure the Problem field on Incident records is populated when incidents are escalated to problems. Use the OOB "Create Problem" UI action or enforce via assignment workflow. The link is stored on the incident.problem_id field — do not rely on custom relationship tables.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"RCA Field Population Rate","order":"320","check_script":"(function(checkDef, dateFilter) {
    var totalGr = new GlideAggregate("problem");
    totalGr.addQuery("state", "IN", "3,4");
    totalGr.addAggregate("COUNT");
    totalGr.query();
    var total = totalGr.next() ? parseInt(totalGr.getAggregate("COUNT")) : 0;

    if (total === 0) {
        return { status: "not_applicable",
            actualValue: "No closed/resolved problem records found (state IN 3,4)",
            finding: "No qualifying closed problem records found. RCA field population cannot be assessed." };
    }

    // Use addNullQuery -- correct API for IS EMPTY on GlideAggregate.
    // addQuery(field, "") treats empty string as literal value and returns 0
    // for rich text (HTML) fields like cause_notes and fix_notes.
    var missingCause = 0;
    try {
        var rcaGA1 = new GlideAggregate("problem");
        rcaGA1.addQuery("state", "IN", "3,4");
        rcaGA1.addNullQuery("cause_notes");
        rcaGA1.addAggregate("COUNT");
        rcaGA1.query();
        missingCause = rcaGA1.next() ? parseInt(rcaGA1.getAggregate("COUNT")) || 0 : 0;
    } catch(e1) {}

    var missingFix = 0;
    try {
        var rcaGA2 = new GlideAggregate("problem");
        rcaGA2.addQuery("state", "IN", "3,4");
        rcaGA2.addNullQuery("fix_notes");
        rcaGA2.addAggregate("COUNT");
        rcaGA2.query();
        missingFix = rcaGA2.next() ? parseInt(rcaGA2.getAggregate("COUNT")) || 0 : 0;
    } catch(e2) {}

    var missingWorkaround = 0;
    try {
        var rcaGA3 = new GlideAggregate("problem");
        rcaGA3.addQuery("state", "IN", "3,4");
        rcaGA3.addNullQuery("work_around");
        rcaGA3.addAggregate("COUNT");
        rcaGA3.query();
        missingWorkaround = rcaGA3.next() ? parseInt(rcaGA3.getAggregate("COUNT")) || 0 : 0;
    } catch(e3) {}

    var causePct    = Math.round(((total - missingCause)    / total) * 100);
    var fixPct      = Math.round(((total - missingFix)      / total) * 100);
    var workarndPct = Math.round(((total - missingWorkaround) / total) * 100);
    // Score only on cause_notes and fix_notes -- workaround is informational
    var worstPct = Math.min(causePct, fixPct);

    var actualValue = total + " closed/resolved problems | " +
        "Cause Notes: " + causePct + "% populated | " +
        "Fix Notes: " + fixPct + "% populated | " +
        "Workaround: " + workarndPct + "% (informational only)";

    if (worstPct >= 80) {
        return { status: "ready", actualValue: actualValue,
            finding: "RCA fields well populated. Cause Notes: " + causePct + "%, Fix Notes: " + fixPct + "%. Strong signal for Now Assist problem summarization and KB article generation." };
    } else if (worstPct >= 50) {
        return { status: "needs_attention", actualValue: actualValue,
            finding: "Partial RCA population (Cause: " + causePct + "%, Fix: " + fixPct + "%, target: 80%+). Now Assist will rely on unstructured work notes for gaps -- enforce RCA field population at problem close." };
    } else {
        return { status: "not_ready", actualValue: actualValue,
            finding: "RCA critically underpopulated (Cause: " + causePct + "%, Fix: " + fixPct + "%). Now Assist problem summarization lacks structured resolution context -- most AI summaries will use unstructured work notes only." };
    }
})()","ai_justification":"cause_notes, fix_notes, and workaround are the structured fields Now Assist reads for problem summaries and KB article generation. High missing rates are critical gaps for AI summarization.","remediation_guidance":"Make Cause Notes and Fix Notes mandatory on problem closure (exclude Cancelled and Duplicate close codes). Configure a closure information mandatory UI policy. Workaround is informational only — it is only required when a workaround was actively used.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Known Error Database (KEDB) Usage","order":"330","check_script":"(function(checkDef, dateFilter) {
    var totalGr = new GlideAggregate("problem");
    totalGr.addQuery("state", "IN", "3,4");
    totalGr.addAggregate("COUNT");
    totalGr.query();
    var total = totalGr.next() ? parseInt(totalGr.getAggregate("COUNT")) : 0;

    if (total === 0) {
        return { status: "not_applicable",
            actualValue: "No closed/resolved problem records found (state IN 3,4)",
            finding: "No qualifying closed problem records. KEDB usage cannot be assessed." };
    }

    // KEDB dual-mechanism:
    // Mechanism 1: primary_known_error_article IS NOT EMPTY
    // (populated by "Create Known Error article" UI action on problem form)
    var keLinked = {};
    var keWithKEA = 0;
    try {
        var ke1 = new GlideRecord("problem");
        ke1.addQuery("state", "IN", "3,4");
        ke1.addNotNullQuery("primary_known_error_article");
        ke1.query();
        while (ke1.next()) {
            keLinked[ke1.getUniqueValue()] = true;
            keWithKEA++;
        }
    } catch(e1) {}

    // Mechanism 2: m2m_kb_task (Attached Knowledge tab on problem)
    var keWithAttached = 0;
    try {
        var m2mGR = new GlideAggregate("m2m_kb_task");
        m2mGR.addAggregate("COUNT");
        m2mGR.groupBy("task");
        m2mGR.query();
        while (m2mGR.next()) {
            var taskId = m2mGR.getValue("task");
            if (!keLinked[taskId]) {
                // Verify it is a closed/resolved problem
                var pCheck = new GlideRecord("problem");
                pCheck.addQuery("sys_id", taskId);
                pCheck.addQuery("state", "IN", "3,4");
                pCheck.setLimit(1);
                pCheck.query();
                if (pCheck.next()) {
                    keLinked[taskId] = true;
                    keWithAttached++;
                }
            }
        }
    } catch(e2) {}

    var knownErrors = Object.keys(keLinked).length;
    var pct = Math.round((knownErrors / total) * 100);
    var actualValue = knownErrors + " of " + total + " closed problems linked to knowledge (" + pct + "%) | " +
        keWithKEA + " via primary_known_error_article | " +
        keWithAttached + " via Attached Knowledge tab only (m2m_kb_task)";

    if (knownErrors >= 10) {
        return { status: "ready", actualValue: actualValue,
            finding: knownErrors + " problems are linked to knowledge. Now Assist can surface these as AI resolution suggestions on related incidents. Continue building the KEDB for high-frequency incident patterns." };
    } else if (knownErrors >= 1) {
        return { status: "needs_attention", actualValue: actualValue,
            finding: "Only " + knownErrors + " problems linked to knowledge (target: 10+). Now Assist KEDB resolution suggestions have limited coverage. " +
            "Two mechanisms: (1) \"Create Known Error article\" UI action populates primary_known_error_article; (2) Attached Knowledge tab (m2m_kb_task)." };
    } else {
        return { status: "not_ready", actualValue: actualValue,
            finding: "KEDB not in active use. Now Assist cannot surface known error resolution suggestions -- a key incident deflection capability. " +
            "Link KB articles to closed problems via the \"Create Known Error article\" UI action or the Attached Knowledge tab." };
    }
})()","ai_justification":"An empty KEDB means Now Assist cannot surface known error workarounds as AI resolution suggestions -- one of the highest-value AI deflection capabilities is completely inactive.","remediation_guidance":"Use the OOB "Create Known Error" UI action on resolved problems to link a Knowledge Base article. This populates the kb_knowledge field (Primary Known Error article). Do not rely on the legacy known_error boolean field — it is deprecated in modern ServiceNow instances and not used by Now Assist.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Major Incident Process Configuration","order":"340","check_script":"(function(checkDef, dateFilter) {
    function getMIRate(priority) {
        var totalGr = new GlideAggregate('incident');
        totalGr.addQuery('priority', priority);
        totalGr.addQuery('state', '!=', -5);
        totalGr.addAggregate('COUNT');
        totalGr.query();
        var total = totalGr.next() ? parseInt(totalGr.getAggregate('COUNT')) : 0;
        if (total === 0) return { total: 0, populated: 0, pct: 0 };

        var popGr = new GlideAggregate('incident');
        popGr.addQuery('priority', priority);
        popGr.addQuery('state', '!=', -5);
        popGr.addQuery('major_incident_state', '!=', '');
        popGr.addAggregate('COUNT');
        popGr.query();
        var populated = popGr.next() ? parseInt(popGr.getAggregate('COUNT')) : 0;

        return { total: total, populated: populated, pct: Math.round((populated / total) * 100) };
    }

    var p1 = getMIRate(1);
    var p2 = getMIRate(2);

    var actualValue = 'P1: ' + p1.populated + '/' + p1.total + ' (' + p1.pct + '%) | P2: ' + p2.populated + '/' + p2.total + ' (' + p2.pct + '%)';

    var p1Status = p1.total === 0 ? 'not_applicable' : p1.pct >= 80 ? 'ready' : p1.pct >= 50 ? 'needs_attention' : 'not_ready';
    var p2Status = p2.total === 0 ? 'not_applicable' : p2.pct >= 30 ? 'ready' : p2.pct >= 10 ? 'needs_attention' : 'not_ready';

    var statusRank = { 'not_ready': 0, 'needs_attention': 1, 'ready': 2, 'not_applicable': 3 };
    var overallStatus = statusRank[p1Status] <= statusRank[p2Status] ? p1Status : p2Status;

    return {
        status: overallStatus,
        actualValue: actualValue,
        finding: 'P1 Major Incident State: ' + p1.pct + '% populated (' + p1.populated + ' of ' + p1.total + '). P2: ' + p2.pct + '% (' + p2.populated + ' of ' + p2.total + '). Now Assist uses major_incident_state to apply MI-specific summarization templates.'
    };
})","ai_justification":"Now Assist applies a dedicated Major Incident summarization template when major_incident_state is set. Low population means most P1/P2 incidents get generic AI summaries instead of richer executive-ready format.","remediation_guidance":"Ensure the Major Incident State field is set on all P1 incidents and on P2 incidents that are formally declared as major incidents. Configure automation or a mandatory UI policy on P1 closure to enforce this. Now Assist applies a dedicated MI summarization template only when major_incident_state is populated.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Major Incident Communication Quality","order":"350","check_script":"(function(checkDef, dateFilter) {
    // P1 incidents total
    var gaTotal = new GlideAggregate('incident');
    gaTotal.addQuery('priority', 1);
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No P1 incidents found',
            finding: 'No P1 incidents found. Major incident communication quality cannot be assessed.'
        };
    }

    // Count distinct P1 incidents that have work notes via sys_journal_field
    // work_notes are stored as journal entries, not a field on incident directly
    var p1Incidents = {};
    var grInc = new GlideRecord('incident');
    grInc.addQuery('priority', 1);
    grInc.query();
    while (grInc.next()) {
        p1Incidents[grInc.getUniqueValue()] = true;
    }

    var p1SysIds = Object.keys(p1Incidents);
    var withNotes = 0;

    if (p1SysIds.length > 0) {
        // Sample check — for large P1 populations check in batches
        var batchSize = Math.min(p1SysIds.length, 500);
        var gaJournal = new GlideAggregate('sys_journal_field');
        gaJournal.addQuery('name', 'incident');
        gaJournal.addQuery('element', 'work_notes');
        gaJournal.addQuery('document_id', 'IN', p1SysIds.slice(0, batchSize).join(','));
        gaJournal.addAggregate('COUNT', 'document_id');
        gaJournal.groupBy('document_id');
        gaJournal.query();
        while (gaJournal.next()) {
            withNotes++;
        }
    }

    var pct = total > 0 ? Math.round((withNotes / total) * 100) : 0;
    var actualValue = pct + '% of P1 incidents have work notes (' + withNotes + ' of ' + total + ')';

    if (pct >= 70) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: pct + '% of P1 incidents have work notes. Now Assist Major Incident summaries and stakeholder briefings have sufficient communication history to generate from.'
        };
    } else if (pct >= 40) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of P1 incidents have work notes (target: 70%). Now Assist Major Incident AI summaries will have limited communication context.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Only ' + pct + '% of P1 incidents have work notes. Now Assist Major Incident summaries are generated from work note content — insufficient notes means poor AI summary quality.'
        };
    }
})","ai_justification":"Work notes are the primary content source for Now Assist Major Incident summaries and stakeholder briefings. High P1 work note coverage gives the AI rich timeline context.","remediation_guidance":"Require work notes on all P1 incidents throughout the lifecycle. Add a UI policy prompting for work notes at key state transitions. Now Assist Major Incident summaries and stakeholder briefings are generated from work note content stored in sys_journal_field.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Post-Incident Review (PIR) Linkage Rate","order":"360","check_script":"(function(checkDef, dateFilter) {
    var totalGr = new GlideAggregate('incident');
    totalGr.addQuery('priority', 1);
    totalGr.addQuery('state', 'IN', '6,7');
    totalGr.addAggregate('COUNT');
    totalGr.query();
    var total = totalGr.next() ? parseInt(totalGr.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return { status: 'not_applicable', actualValue: 'No resolved/closed P1 incidents found',
            finding: 'No resolved P1 incidents found. PIR linkage cannot be assessed.' };
    }

    var linkedGr = new GlideAggregate('incident');
    linkedGr.addQuery('priority', 1);
    linkedGr.addQuery('state', 'IN', '6,7');
    linkedGr.addQuery('problem_id', '!=', '');
    linkedGr.addAggregate('COUNT');
    linkedGr.query();
    var linked = linkedGr.next() ? parseInt(linkedGr.getAggregate('COUNT')) : 0;

    var pct = Math.round((linked / total) * 100);
    var actualValue = linked + ' of ' + total + ' resolved P1 incidents linked to a Problem record (' + pct + '%)';

    if (pct >= 80) {
        return { status: 'ready', actualValue: actualValue,
            finding: pct + '% of P1 incidents linked to a problem record. Now Assist can surface recurring P1 patterns and PIR-driven recommendations.' };
    } else if (pct >= 50) {
        return { status: 'needs_attention', actualValue: actualValue,
            finding: 'Only ' + pct + '% of P1 incidents linked to a problem (target: 80%). PIR recommendations will have incomplete data.' };
    } else {
        return { status: 'not_ready', actualValue: actualValue,
            finding: 'Only ' + pct + '% of P1 incidents are linked to a problem record. Now Assist cannot surface recurring major incident patterns or PIR insights.' };
    }
})","ai_justification":"Post-incident review data allows Now Assist to identify systemic failure patterns and generate recurrence prevention recommendations. Low PIR coverage means this AI capability has no historical data.","remediation_guidance":"Link all resolved P1 incidents to a Problem record using the OOB Problem field (problem_id). Enforce via a mandatory field policy on P1 resolution or an automated workflow that creates a problem record for every P1. Do not use custom relationship tables — Now Assist reads the OOB problem_id reference field.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Assignment Group Membership and Manager Population","order":"370","check_script":"(function(checkDef, dateFilter) {
    var totalGr = new GlideAggregate('sys_user_group');
    totalGr.addQuery('active', true);
    totalGr.addQuery('type', 'itil');
    totalGr.addAggregate('COUNT');
    totalGr.query();
    var total = totalGr.next() ? parseInt(totalGr.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return { status: 'not_applicable', actualValue: 'No active ITSM groups found',
            finding: 'No active ITSM assignment groups found. Group membership cannot be assessed.' };
    }

    var withMembers = 0;
    var groupGr = new GlideRecord('sys_user_group');
    groupGr.addQuery('active', true);
    groupGr.addQuery('type', 'itil');
    groupGr.query();
    while (groupGr.next()) {
        var memGr = new GlideRecord('sys_user_grmember');
        memGr.addQuery('group', groupGr.getUniqueValue());
        memGr.setLimit(1);
        memGr.query();
        if (memGr.next()) withMembers++;
    }

    var withManagerGr = new GlideAggregate('sys_user_group');
    withManagerGr.addQuery('active', true);
    withManagerGr.addQuery('type', 'itil');
    withManagerGr.addQuery('manager', '!=', '');
    withManagerGr.addAggregate('COUNT');
    withManagerGr.query();
    var withManager = withManagerGr.next() ? parseInt(withManagerGr.getAggregate('COUNT')) : 0;

    var memberPct = Math.round((withMembers / total) * 100);
    var managerPct = Math.round((withManager / total) * 100);
    var worstPct = Math.min(memberPct, managerPct);

    var actualValue = 'Total ITSM groups: ' + total + ' | With members: ' + memberPct + '% | With manager: ' + managerPct + '%';
    var cloneNote = 'NOTE: If running on a non-production clone, sys_user data is typically stripped — verify on production before treating as a blocker. ';

    if (worstPct >= 80) {
        return { status: 'ready', actualValue: actualValue,
            finding: cloneNote + 'Assignment groups are well configured. AI Agent routing has valid group membership and manager data.' };
    } else if (worstPct >= 50) {
        return { status: 'needs_attention', actualValue: actualValue,
            finding: cloneNote + 'Group membership (' + memberPct + '%) or manager assignment (' + managerPct + '%) below target. AI Agent routing may fail for some groups.' };
    } else {
        return { status: 'not_ready', actualValue: actualValue,
            finding: cloneNote + 'Group membership (' + memberPct + '%) and/or manager (' + managerPct + '%) critically low. AI Agent routing will not function correctly without populated groups.' };
    }
})","ai_justification":"Groups with no members create silent AI Agent routing failures -- work is assigned correctly but never actioned. Groups with no manager cannot escalate automatically.","remediation_guidance":"Populate group membership and manager fields on active ITSM groups via sys_user_group_list.do. Use import sets to bulk-assign from HR data. Groups with no members create silent AI Agent routing failures -- work is assigned but never actioned.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Flow Designer Adoption on Incident and Change","order":"380","check_script":"(function(checkDef, dateFilter) {
    // Count active Flow Designer flows (all) — AI Agents use FD exclusively
    var gaFlows = new GlideAggregate('sys_hub_flow');
    gaFlows.addQuery('active', true);
    gaFlows.addAggregate('COUNT');
    gaFlows.query();
    var flows = gaFlows.next() ? parseInt(gaFlows.getAggregate('COUNT')) : 0;

    // Count active legacy Workflow Engine processes on incident/change
    var gaLegacy = new GlideAggregate('wf_workflow');
    gaLegacy.addQuery('active', true);
    gaLegacy.addQuery('table', 'IN', 'incident,change_request');
    gaLegacy.addAggregate('COUNT');
    gaLegacy.query();
    var legacy = gaLegacy.next() ? parseInt(gaLegacy.getAggregate('COUNT')) : 0;

    var actualValue = flows + ' active Flow Designer flows | ' + legacy + ' legacy Workflow Engine processes on incident/change';

    if (flows > 0 && legacy === 0) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: flows + ' active Flow Designer flows with no legacy Workflow Engine processes on incident/change. AI Agents have a clean Flow Designer foundation for ITSM orchestration.'
        };
    } else if (flows > 0 && legacy > 0) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: flows + ' Flow Designer flows active but ' + legacy + ' legacy Workflow Engine process(es) still exist on incident/change. Migrate legacy workflows to Flow Designer — AI Agents orchestrate exclusively through Flow Designer.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'No active Flow Designer flows found. AI Agents exclusively orchestrate ITSM automation through Flow Designer — without flows, AI Agent automation cannot execute on incident or change.'
        };
    }
})","ai_justification":"AI Agents orchestrate ITSM automation exclusively through Flow Designer subflows. High Flow Designer adoption means the full AI Agent collection can orchestrate without legacy compatibility issues.","remediation_guidance":"Create Flow Designer flows for key ITSM processes. Migrate legacy Workflow Engine processes on incident and change to Flow Designer subflows using the Workflow Migration tool. AI Agents orchestrate ITSM automation exclusively through Flow Designer.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITSM","check_name":"Agentic AI Customization Risk on Task Table","order":"390","check_script":"(function(checkDef, dateFilter) {
    var gaBR = new GlideAggregate('sys_script');
    gaBR.addQuery('collection', 'task');
    gaBR.addQuery('active', true);
    gaBR.addQuery('sys_created_by', 'NOT IN', 'glide.maint,system,admin,fred.luddy');
    gaBR.addAggregate('COUNT');
    gaBR.query();
    var brs = gaBR.next() ? parseInt(gaBR.getAggregate('COUNT')) : 0;

    var gaACL = new GlideAggregate('sys_security_acl');
    gaACL.addQuery('name', 'task');
    gaACL.addAggregate('COUNT');
    gaACL.query();
    var acls = gaACL.next() ? parseInt(gaACL.getAggregate('COUNT')) : 0;

    var risk = brs + acls;
    var actualValue = brs + ' custom BRs on task | ' + acls + ' ACLs on task | Combined risk score: ' + risk;

    if (risk <= 10) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: 'Low Agentic AI customization risk on task table (score: ' + risk + '). AI Agent read/write operations are unlikely to encounter conflicts.'
        };
    } else if (risk <= 25) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Moderate Agentic AI customization risk on task table (score: ' + risk + '). Test AI Agent actions in sub-production to identify Business Rule or ACL conflicts before go-live.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'High Agentic AI customization risk on task table (score: ' + risk + '). Extensive customization creates significant risk of AI Agent conflicts on read/write operations — review and reduce before AI Agent enablement.'
        };
    }
})","ai_justification":"Business rules and ACLs on the task table can intercept or modify AI Agent read/write actions, causing silent failures or unpredictable behavior.","remediation_guidance":"Review and reduce custom Business Rules and ACLs on the task table before Agentic AI enablement. Test AI Agent actions in sub-production to identify conflicts. Disable non-essential Business Rules that may intercept AI Agent read/write operations.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_ITSM'
};
